  "scoring_guide": {
    "waypoints": [
      {
        "id": "FoI4",
        "credit": 3,
        "rule": "Q1 = b. No AND (Q2 selections include options 1 AND 2) AND (Q3 selections include option 1 AND at least one of {2,4}). Additionally, at least one decision-oriented selection across Q2 or Q3 (Q2 option 3 OR Q3 option 6) is present."
      },
      {
        "id": "FoI3P",
        "credit": 2,
        "rule": "Q1 = b. No AND practical-magnitude reasoning is present without full integration: (Q2 includes option 1) AND (Q3 includes at least one of {2,4,6}) AND (Q3 option 1 is NOT selected OR Q2 option 2 is NOT selected)."
      },
      {
        "id": "FoI2P",
        "credit": 1,
        "rule": "Q1 = b. No AND minimal practical reasoning is present: (Q2 includes option 1 OR 3 OR Q3 includes option 4 OR 6) BUT conditions for FoI3P and FoI4 are not met."
      },
      {
        "id": "FoI1",
        "credit": 0,
        "rule": "Q1 = b. No AND responses rely only on subjective or incorrect statements (no keyed options selected in Q2 or Q3) OR selections primarily reflect misconceptions without any keyed selections."
      },
      {
        "id": "FoI0",
        "credit": 0,
        "rule": "No selections made on Q2 and Q3 (blank), regardless of Q1."
      }
    ],
    "notes": "Scoring prioritizes the presence of key warrants and integration. No penalty for isolated distractor selections unless they directly contradict the claim. Contradiction cap: if two or more conflation distractors are selected (Q2 option 4 or 7; Q3 option 3 or 7), maximum credit is capped at FoI2P (1 point). This mirrors the CR rubric’s emphasis on explicit coordination of statistical and practical significance and decision relevance."
  },
  "note": "Difficulty is targeted by requiring both magnitude-in-context and explicit stat–practical coordination for top credit. Distractors reflect common misconceptions: conflating p with practical importance, misreading sample size, assuming any nonzero difference matters, overgeneralizing representativeness, uncertainty fallacy, and design fatalism. Option homogeneity and absence of cues align with Haladyna & Rodriguez best practices."
